mapper.select:
SELECT tingchechangmingcheng, quyu, chewei_count, free_count
FROM v_stat_chewei_dim


		AND tingchechangmingcheng = #{lot}


		AND quyu = #{quyu}

SELECT COUNT(*) FROM tingchejiaofei
WHERE lichangshijian IS NOT NULL
  AND lichangshijian >= #{start} AND lichangshijian <= #{end}

SELECT COUNT(*) FROM chewei_yuyue
WHERE zhuangtai = '已取消'
  AND addtime >= #{start} AND addtime <= #{end}

SELECT COUNT(*) FROM tingche_bujiao
WHERE leixing = '超时补缴'
  AND addtime >= #{start} AND addtime <= #{end}

SELECT
	CASE WHEN TRIM(IFNULL(tingchechangmingcheng, '')) = '' THEN '未命名车场' ELSE TRIM(tingchechangmingcheng) END AS tingchechangmingcheng,
	IFNULL(quyu, '') AS quyu,
	COUNT(*) AS ruchang_count
FROM chezijinchang
WHERE jinchangshijian >= #{start} AND jinchangshijian <= #{end}

	AND tingchechangmingcheng = #{lot}


	AND quyu = #{quyu}

GROUP BY 1, 2

SELECT stat_date, SUM(lichang_count) AS lichang_count, SUM(parking_revenue) AS parking_revenue, SUM(duration_sum_hours) AS duration_sum_hours, SUM(duration_cnt) AS duration_cnt FROM v_stat_revenue_daily WHERE stat_date >= DATE(#{start}) AND stat_date <= DATE(#{end})
AND tingchechangmingcheng = #{lot}
AND quyu = #{quyu}
GROUP BY stat_date ORDER BY stat_date

SELECT DATE(b.addtime) AS stat_date, IFNULL(SUM(b.jine), 0) AS bujiao_revenue
FROM tingche_bujiao b
LEFT JOIN chezijinchang c ON c.id = b.chezijinchang_id
WHERE b.zhuangtai = '已支付'
  AND b.addtime >= #{start} AND b.addtime <= #{end}

	AND c.tingchechangmingcheng = #{lot}


	AND c.quyu = #{quyu}

GROUP BY DATE(b.addtime)
ORDER BY stat_date

SELECT tingchechangmingcheng, quyu, SUM(lichang_count) AS lichang_count, SUM(parking_revenue) AS parking_revenue, SUM(duration_sum_hours) AS duration_sum_hours, SUM(duration_cnt) AS duration_cnt FROM v_stat_revenue_daily WHERE stat_date >= DATE(#{start}) AND stat_date <= DATE(#{end})
AND tingchechangmingcheng = #{lot}
AND quyu = #{quyu}
GROUP BY tingchechangmingcheng, quyu
